int cmp_asc(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int arr[] = {5, 2, 8, 1, 9};
    int n = 5;
    qsort(arr, n, sizeof(int), cmp_asc);
    for (int i = 0; i < n; i++)
        printf("%d ", arr[i]);
    // 1 2 5 8 9
}

