typedef struct { int id; int score; } Student;

int cmp_by_score(const void *a, const void *b) {
    Student *sa = (Student*)a;
    Student *sb = (Student*)b;
    return sb->score - sa->score;  // descending by score
}

int main() {
    Student arr[] = {{1, 85}, {2, 92}, {3, 78}};
    qsort(arr, 3, sizeof(Student), cmp_by_score);
    for (int i = 0; i < 3; i++)
        printf("id=%d score=%d\n", arr[i].id, arr[i].score);
    // id=2 score=92
    // id=1 score=85
    // id=3 score=78
}

