typedef struct { int a; int b; } Pair;

int cmp_pair(const void *x, const void *y) {
    Pair *px = (Pair*)x;
    Pair *py = (Pair*)y;
    if (px->a != py->a)
        return px->a - py->a;
    return py->b - px->b;
}

int main() {
    Pair arr[] = {{2, 5}, {1, 3}, {2, 8}, {1, 7}};
    qsort(arr, 4, sizeof(Pair), cmp_pair);
    for (int i = 0; i < 4; i++)
        printf("%d %d\n", arr[i].a, arr[i].b);
    return 0;
}
